const body = $json.body;
const products = body.products || [];
const dest = body.destination || {};

const toWid  = dest.wid  || '120363407963539220@g.us';
const toName = dest.name || 'Grupo Teste';

if (!products.length) return [];

return products.map((p, i) => ({
  json: {
    ordem: i + 1,
    total: products.length,
    to:    toWid,
    dest_name: toName,
    item_id: p.id || '',
    title: p.name || '',
    price: p.price || '',
    shop:  p.shop || '',
    commission_rate:  p.commission_rate || '',
    commission_value: p.commission_value || '',
    sales: parseInt(p.sales || 0),
    product_url:   p.product_url || '',
    affiliate_url: p.affiliate_url || ''
  }
}));

// ═══════════════════════════════════════════════════════════════
// 🧹 PARSER + FORMATADOR — NERD MISSION CONTROL V2
// Mensagens de curadoria manual, estilo nerd/apaixonado por tech
// ═══════════════════════════════════════════════════════════════
const p = $('🔀 Separar Produtos').item.json;
const apiResp = $json;

// ── IMAGEM ──────────────────────────────────────────────────────
let imageUrl = '';
try {
  const item = apiResp?.data?.item;
  if (item?.images?.length > 0) {
    imageUrl = 'https://cf.shopee.com.br/file/' + item.images[0];
  } else if (item?.image) {
    imageUrl = 'https://cf.shopee.com.br/file/' + item.image;
  }
} catch(e) {}

// Fallback via URL do produto
if (!imageUrl) {
  const matchImg = p.product_url.match(/\/product\/(\d+)\/(\d+)/);
  if (matchImg) imageUrl = `https://cf.shopee.com.br/file/${matchImg[2]}_tn`;
}

// ── PREÇO ────────────────────────────────────────────────────────
const precoNum = parseFloat(String(p.price || '0').replace(',', '.'));
const precoFmt = 'R$ ' + precoNum.toLocaleString('pt-BR', { minimumFractionDigits: 2, maximumFractionDigits: 2 });

// ── VENDAS / VIRAL ────────────────────────────────────────────────
const vendas = parseInt(p.sales || 0);
const isViral = vendas >= 500;
const isMuitoViral = vendas >= 2000;

// ── HORÁRIO BR ────────────────────────────────────────────────────
const horaBR = (new Date().getUTCHours() - 3 + 24) % 24;
let periodo;
if (horaBR >= 5 && horaBR < 9)   periodo = 'MANHA_CEDO';
else if (horaBR >= 9 && horaBR < 12)  periodo = 'MANHA';
else if (horaBR >= 12 && horaBR < 14) periodo = 'ALMOCO';
else if (horaBR >= 14 && horaBR < 18) periodo = 'TARDE';
else if (horaBR >= 18 && horaBR < 22) periodo = 'NOITE';
else periodo = 'MADRUGADA';

// ═══════════════════════════════════════════════════════════════
// MENSAGENS DE CURADORIA — estilo pessoal, nerd, apaixonado
// Formato: título especial + contexto pessoal + produto + CTA
// ═══════════════════════════════════════════════════════════════
const ESPACO = '⠀';

// ── TÍTULOS ESPECIAIS (curadoria manual) ─────────────────────────
const titulosNerd = [
  '🤓 *HORA DO NERD — achado especial!*',
  '🛸 *TECH ESCOLHIDO A DEDO — só pra vocês!*',
  '🧪 *LAB DO NERD: produto aprovado!*',
  '🎯 *GARIMPEI PRA VOCÊS — olha só isso!*',
  '🔬 *UNDER THE RADAR — achei antes de todo mundo*',
  '⚡ *ALERTA NERD — produto no radar!*',
  '🏆 *CURADORIA NERD — selecionei com carinho*'
];

const titulosManha = [
  '☕ *ACHEI ISSO DE MANHÃ — tinha que compartilhar!*',
  '🌅 *BOM DIA COM OFERTA NERD!*',
  '🧠 *ANTES DO CAFÉ — já garimpei pra vocês*'
];

const titulosAlmoco = [
  '🍕 *PAUSA DO ALMOÇO BEM APROVEITADA...*',
  '⏸️ *DEI UMA PAUSA E ACHEI ISSO*',
  '🍽️ *ENTRE UMA GARFADA E OUTRA — oferta nerd!*'
];

const titulosTarde = [
  '🌤️ *TARDE PRODUTIVA: garimpei esse pra vocês*',
  '☕ *CAFÉ DA TARDE + ACHADO TECH*',
  '🔍 *FUÇANDO A INTERNET AQUI...*'
];

const titulosNoite = [
  '🌙 *NOITE DO NERD — achado especial*',
  '🦉 *CORUJA TECH: procurando enquanto vocês dormem*',
  '🌃 *DEPOIS DO DIA — separei isso pra vocês*',
  '😴 *ANTES DE DORMIR — compartilha que é bom demais*'
];

const titulosViralNerd = [
  '🔥 *TODO NERD TÁ COMPRANDO ESSE!*',
  '📈 *VIRAL NA SHOPEE — e eu entendo o porquê*',
  '🚀 *PRODUTO DO MOMENTO — garimpado com aprovação!*'
];

// ── MENSAGEM PESSOAL (contextual) ─────────────────────────────────
const mensagensPessoais = [
  '_Tava dando uma olhada na Shopee e não resisti em compartilhar..._',
  '_Garimpei isso aqui no meu tempo livre — achei demais!_',
  '_Vi isso e lembrei de vocês do grupo. Preço absurdo!_',
  '_Não consigo guardar bom achado só pra mim. 😅 Olha isso:_',
  '_Esse aqui passou pelo meu radar e eu fui checar. Valeu cada segundo!_',
  '_Filtrei manualmente pra trazer o que tem mais a ver com a galera aqui._',
  '_Curadoria 100% manual — sem algoritmo, só olho clínico de nerd. 🧠_',
  '_Achado raro esses dias. Não encontra assim em todo lugar._'
];

const mensagensManha = [
  '_Manhã produtiva aqui: já garimpei oferta antes mesmo do café esfriar! ☕_',
  '_Acordei, fui na Shopee, achei isso. Bom dia! 😅_'
];

const mensagensAlmoco = [
  '_Aproveitei a pausa do almoço pra garimpar essa joia aqui._',
  '_Entre uma tarefa e outra, achei isso na Shopee. 😂_'
];

const mensagensNoite = [
  '_Trabalhei o dia todo e ainda achei um tempinho pra garimpar pra vocês. 🌙_',
  '_Final do dia, mas o nerd não descansa. Olha o que eu achei!_'
];

// ── SELECIONA TÍTULO ───────────────────────────────────────────────
let titulo;
if (isMuitoViral) {
  titulo = titulosViralNerd[Math.floor(Math.random() * titulosViralNerd.length)];
} else {
  const poolTitulos = [...titulosNerd];
  if (periodo === 'MANHA_CEDO' || periodo === 'MANHA') poolTitulos.push(...titulosManha);
  else if (periodo === 'ALMOCO') poolTitulos.push(...titulosAlmoco);
  else if (periodo === 'TARDE') poolTitulos.push(...titulosTarde);
  else poolTitulos.push(...titulosNoite);
  titulo = poolTitulos[Math.floor(Math.random() * poolTitulos.length)];
}

// ── SELECIONA MENSAGEM PESSOAL ─────────────────────────────────────
let msgPessoal;
const poolMsg = [...mensagensPessoais];
if (periodo === 'MANHA_CEDO' || periodo === 'MANHA') poolMsg.push(...mensagensManha);
else if (periodo === 'ALMOCO') poolMsg.push(...mensagensAlmoco);
else if (periodo === 'NOITE' || periodo === 'MADRUGADA') poolMsg.push(...mensagensNoite);
msgPessoal = poolMsg[Math.floor(Math.random() * poolMsg.length)];

// ── BADGES ───────────────────────────────────────────────────────
const vendaBadge = isMuitoViral
  ? '\n🔥 *+' + vendas + ' vendidos* — tá bombando!'
  : isViral ? '\n📈 *' + vendas + ' vendidos* na Shopee' : '';

const commBadge = p.commission_value
  ? '\n💸 _Comissão: ' + p.commission_rate + ' (' + p.commission_value + ')_'
  : '';

// ── ENCURTAR LINK ─────────────────────────────────────────────────
let linkFinal = p.affiliate_url || p.product_url || '';
try {
  const r = await this.helpers.httpRequest({
    method: 'GET',
    url: 'https://tinyurl.com/api-create.php?url=' + encodeURIComponent(linkFinal),
    timeout: 8000
  });
  const limpo = String(r).trim();
  if (limpo.startsWith('https://tinyurl.com/')) linkFinal = limpo;
} catch(e) {}

// ── MONTA MENSAGEM FINAL ──────────────────────────────────────────
const parts = [
  titulo,
  ESPACO,
  msgPessoal,
  ESPACO,
  '📦 *' + p.title + '*',
  ESPACO,
  '💰 *R$ ' + p.price + '*'
];

if (commBadge)  parts.push(commBadge);
if (vendaBadge) parts.push(vendaBadge);

parts.push(ESPACO);
parts.push('🛒 *Garanta o seu agora:*');
parts.push(linkFinal);
parts.push(ESPACO);
parts.push('🔒 _Compra segura pela Shopee_');
parts.push('━━━━━━━━━━━━━━━━━');

const message = parts.join('\n');

// ── DESTINO (modo) ─────────────────────────────────────────────────
// group  = 120363407963539220-group (teste)
// channel = 120363425991429905@newsletter (canal oficial)
const destinos = {
  group:   '120363407963539220@g.us',
  channel: '120363425991429905@newsletter'
};
const to = destinos[p.mode] || destinos.group;

return [{
  json: {
    status: 'pronto',
    title: p.title,
    price: precoFmt,
    image: imageUrl,
    message,
    link: linkFinal,
    to,
    ordem: p.ordem,
    total: p.total
  }
}];
